// HasTenant applies the HasEdge predicate on the "tenant" edge.
func HasTenant() predicate.ReportWorkflowSchedule {
	return predicate.ReportWorkflowSchedule(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, false, TenantTable, TenantColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasTenantWith applies the HasEdge predicate on the "tenant" edge with a given conditions (other predicates).
func HasTenantWith(preds ...predicate.Tenant) predicate.ReportWorkflowSchedule {
	return predicate.ReportWorkflowSchedule(func(s *sql.Selector) {
		step := newTenantStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ReportWorkflowSchedule) predicate.ReportWorkflowSchedule {
	return predicate.ReportWorkflowSchedule(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ReportWorkflowSchedule) predicate.ReportWorkflowSchedule {
	return predicate.ReportWorkflowSchedule(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ReportWorkflowSchedule) predicate.ReportWorkflowSchedule {
	return predicate.ReportWorkflowSchedule(sql.NotPredicates(p))
}
